<template>
  <div class="playlists-cont">
    <div class="top-card">
      <div class="icon-wrap">
        <img :src="topList.coverImgUrl" alt="" />
      </div>
      <div class="card-wrap">
        <div class="tag">精品歌单</div>
        <p class="title">
          {{topList.name}}
        </p>
        <div class="info">
          {{topList.description}}
        </div>
      </div>
      <img class="cover-img" src="@/assets/listCover.jpg" alt="" />
      <div class="bg-mask"></div>
    </div>
    <div class="tab-cont">
      <div class="tab-bar">
        <ul>
          <li :class="{ active: tag == '全部' }" @click="tag = '全部'">全部</li>
          <li :class="{ active: tag == '欧美' }" @click="tag = '欧美'">欧美</li>
          <li :class="{ active: tag == '华语' }" @click="tag = '华语'">华语</li>
          <li :class="{ active: tag == '流行' }" @click="tag = '流行'">流行</li>
          <li :class="{ active: tag == '说唱' }" @click="tag = '说唱'">说唱</li>
          <li :class="{ active: tag == '摇滚' }" @click="tag = '摇滚'">摇滚</li>
          <li :class="{ active: tag == '民谣' }" @click="tag = '民谣'">民谣</li>
          <li :class="{ active: tag == '电子' }" @click="tag = '电子'">电子</li>
          <li :class="{ active: tag == '轻音乐' }" @click="tag = '轻音乐'">轻音乐</li>
          <li :class="{ active: tag == '影视原声' }" @click="tag = '影视原声'"> 影视原声</li>
          <li :class="{ active: tag == 'ACG' }" @click="tag = 'ACG'">ACG</li>
          <li :class="{ active: tag == '怀旧' }" @click="tag = '怀旧'">怀旧</li>
          <li :class="{ active: tag == '治愈' }" @click="tag = '治愈'">治愈</li>
          <li :class="{ active: tag == '旅行' }" @click="tag = '旅行'">旅行</li>
        </ul>
      </div>
      <div class="items">
        <div class="item" v-for="(item, i) in lists" :key="i" @click="$router.push('/playlist?id='+item.id)">
          <div class="img-wrap">
            <img :src="item.coverImgUrl" alt="" />
            <div class="desc-wrap">
              <span>播放量：{{item.playCount| getCount}}</span>
            </div>
            <span class="iconfont icon-icon_play_default"></span>
          </div>
          <p class="name">{{item.name}}</p>
        </div>
      </div>
    </div>
    <el-pagination
    @current-change="handleCurrentChange"
    background
    layout="prev, pager, next"
    :total="total"
    :current-page="page"
    :page-size="20"
  >
  </el-pagination>
  </div>
</template>

<script>
import music from "@/api/music"
export default {
  name: "Playlists",
  data() {
    return {
      tag: "全部",
      topList:[],
      lists:[],
       // 总条数
      total: 0,
      // 页码
      page: 1,
    };
  },
  watch:{
    tag(){
    this.page = 1
    this.topData()
    this.goListData()
    }
  },
  methods: {
    // 顶部数据
    async topData() {
      const res = await music.getPlaylists({
        params:{
          limit:1,
          cat:this.tag
        }
      })
      // console.log(res)
      this.topList = res.playlists[0]
    },
    async goListData() {
      const res = await music.getTopList({
        params:{
          limit:12,
          cat:this.tag,
          offset:(this.page-1)*10
        }
      })
      // console.log(res)
      this.lists = res.playlists
      this.total = res.total
    },
    handleCurrentChange(index){
      this.page = index
      this.goListData()
    }
  },
  created(){
    this.page = 1
    this.topData()
    this.goListData()
  }
};
</script>

<style lang="scss" scoped>
.playlists-cont {
  .top-card {
    border-radius: 5px;
    height: 200px;
    display: flex;
    padding: 20px;
    position: relative;
    overflow: hidden;
    .icon-wrap {
      margin-right: 20px;
      z-index: 1;
      img {
        width: 160px;
        height: 160px;
      }
    }
    .card-wrap {
      z-index: 1;
      .tag {
        color: #dfac67;
        border: 1px solid #dfac67;
        width: 100px;
        height: 30px;
        text-align: center;
        border-radius: 5px;
        font-size: 16px;
        line-height: 30px;
        cursor: pointer;
        margin-bottom: 10px;
      }
      .title {
        color: #fff;
      }
      .info {
        color: #888482;
        font-size: 14px;
        padding-top: 5px;
        overflow: hidden;
        text-overflow: ellipsis;
        display: -webkit-box;
        -webkit-box-orient: vertical;
        -webkit-line-clamp: 5;
      }
    }
    .cover-img {
      width: 100%;
      position: absolute;
      left: 0;
      top: 0;
      right: 0;
      bottom: 0;
      z-index: 0;
      -webkit-filter: blur(20px);
      filter: blur(20px);
    }
    .bg-mask {
      width: 100%;
      position: absolute;
      left: 0;
      top: 0;
      right: 0;
      bottom: 0;
      background-color: rgba(0, 0, 0, 0.5);
    }
  }
  .tab-cont {
    padding-top: 30px;
    .tab-bar {
       margin-bottom: 20px;
      ul {
        display: flex;
        justify-content: flex-end;
        align-items: center;
        li {
          margin-right: 20px;
          color: #808080;
          cursor: pointer;
        }
        .active {
          color: #dd6d60;
        }
      }
    }
     .items {
      display: flex;
      flex-wrap: wrap;
      .item {
        width: 200px;
        margin: 10px;
        overflow: hidden;
        &:hover {
          .img-wrap .desc-wrap {
            top: 0px;
          }
        }
        .img-wrap {
          width: 100%;
          position: relative;
          cursor: pointer;
          &:hover {
            .iconfont {
              opacity: 1;
            }
          }
          img {
            width: 200px;
            height: 200px;
            border-radius: 10px;
          }
          .desc-wrap {
            width:100%;
            position: absolute;
            left: 0;
            top: -50px;
            background: rgba(0, 0, 0, 0.5);
            color: #fff;
            padding: 5px;
            overflow: hidden;
            text-overflow: ellipsis;
            display: -webkit-box;
            -webkit-box-orient: vertical;
            -webkit-line-clamp: 2;
            span {
              font-size: 14px;
            }
          }
          .iconfont {
            position: absolute;
            right: 10px;
            bottom: 13px;
            width: 40px;
            height: 40px;
            color: #dd6d60;
            font-size: 20px;
            border-radius: 50%;
            display: -webkit-box;
            display: -ms-flexbox;
            display: flex;
            -webkit-box-align: center;
            -ms-flex-align: center;
            align-items: center;
            -webkit-box-pack: center;
            -ms-flex-pack: center;
            justify-content: center;
            background: rgba(255, 255, 255, 0.8);
            opacity: 0;
          }
          .icon-icon_play_default:before {
            transform: translateX(3px);
          }
        }
      }
    }
  }
}
</style>
